import sys, types, threading, time

from assay_engine.persistence import checkpoint as cp

state = {"setup_on": [], "lock_on": [], "pools": []}

class FakeConn:
    def execute(self, sql, params=None):
        if "pg_advisory_lock" in sql:
            state["lock_on"].append(id(self))

class FakePool:
    check_connection = staticmethod(lambda *a, **k: None)
    def __init__(self, conn_str, **kw):
        self._conn = FakeConn()
        state["pools"].append(self)
    def connection(self):
        conn = self._conn
        class _Ctx:
            def __enter__(self_): return conn
            def __exit__(self_, *a): return False
        return _Ctx()
    def close(self): pass

class FakeSaver:
    def __init__(self, arg): self.arg = arg
    def setup(self):
        time.sleep(0.001)   # widen the check->set window
        state["setup_on"].append(id(self.arg))

def _mod(name, **attrs):
    m = types.ModuleType(name)
    for k, v in attrs.items(): setattr(m, k, v)
    sys.modules[name] = m
    return m

_mod("langgraph"); _mod("langgraph.checkpoint")
_mod("langgraph.checkpoint.postgres", PostgresSaver=FakeSaver)
_mod("langgraph.checkpoint.memory", MemorySaver=type("MemorySaver", (), {}))
_mod("psycopg"); _mod("psycopg.rows", dict_row=object())
_mod("psycopg_pool", ConnectionPool=FakePool)

import os
os.environ["ASSAY_POSTGRES_URL"] = "postgresql://localhost:5432/assay"

def run(remove_lock):
    cp._INITIALIZED_CONN_STRS = set()
    cp._OPEN_POOLS = []
    cp._atexit_registered = True  # avoid touching atexit
    state["setup_on"].clear(); state["lock_on"].clear(); state["pools"].clear()

    if remove_lock:
        # simulate the bootstrap block WITHOUT the _init_lock guard, mirroring checkpoint.py logic
        from psycopg_pool import ConnectionPool
        from langgraph.checkpoint.postgres import PostgresSaver
        conn_str = cp.get_postgres_connection_string()
        def unlocked_get():
            pool = ConnectionPool(conn_str, open=True)
            cp._OPEN_POOLS.append(pool)
            # NO with _init_lock here:
            if conn_str not in cp._INITIALIZED_CONN_STRS:
                with pool.connection() as conn:
                    conn.execute("SELECT pg_advisory_lock(%s)", (cp._MIGRATION_LOCK_KEY,))
                    PostgresSaver(conn).setup()
                cp._INITIALIZED_CONN_STRS.add(conn_str)
            return PostgresSaver(pool)
        target = unlocked_get
    else:
        target = cp.get_checkpointer

    n = 8
    barrier = threading.Barrier(n)
    def worker():
        barrier.wait()
        target()
    ts = [threading.Thread(target=worker) for _ in range(n)]
    for t in ts: t.start()
    for t in ts: t.join()
    return len(state["setup_on"])

print("WITH    lock (real get_checkpointer): setup ran", run(remove_lock=False), "times")
print("WITHOUT lock (simulated):             setup ran", run(remove_lock=True), "times")
